import copy

def sensitivity_analysis(base_model: TCOModel, param_name: str,
                         low_factor: float, high_factor: float) -> dict:
    """Vary a scalar attribute by low/high factors and report NPV range."""
    results = {}
    for label, factor in [("low", low_factor), ("base", 1.0), ("high", high_factor)]:
        m = copy.deepcopy(base_model)
        if param_name == "calls_per_month":
            m.api_profile.calls_per_month = int(
                base_model.api_profile.calls_per_month * factor
            )
        elif param_name == "oversight_fte":
            m.oversight_fte = base_model.oversight_fte * factor
        elif param_name == "annual_growth_rate":
            m.annual_growth_rate = base_model.annual_growth_rate * factor
        results[label] = round(m.npv(), 0)
    results["swing"] = results["high"] - results["low"]
    return {"parameter": param_name, **results}

# Run sensitivity on the build model
params = [
    ("calls_per_month",  0.5, 3.0),
    ("oversight_fte",    0.5, 2.0),
    ("annual_growth_rate", 0.5, 2.0),
]
for param, lo, hi in params:
    r = sensitivity_analysis(build_model, param, lo, hi)
    print(f"{r['parameter']:25s}  low=${r['low']:>10,.0f}  "
          f"base=${r['base']:>10,.0f}  high=${r['high']:>10,.0f}  "
          f"swing=${r['swing']:>10,.0f}")
